THE CLAIM:
{
 "title": "CE hyperscale share set at 0.44 is too high; real weight is colocation",
 "narrative": "The model applies Synergy's global capacity split, giving hyperscale a 0.44 share of Central European demand. But CBRE's Europe data shows about 60% of hyperscaler self-build sits in Ireland, the Netherlands, Sweden and Belgium, and colocation stays larger than self-build. In Central Europe, hyperscalers mostly rent colo space in Frankfurt, so the biggest model cell is largely empty and the real mix tilts to colocation buyers.",
 "mechanism": [
  {
   "step": "trigger",
   "text": "CBRE Q4-2025: 60% of Europe self-build sits outside CE-7; colocation stays larger",
   "refs": [
    "digest:seg-mix#c16",
    "digest:seg-mix#c15"
   ]
  },
  {
   "step": "propagation",
   "text": "The 0.44 came from a global figure, never measured in Europe",
   "refs": [
    "ledger:seg.hyperscale",
    "digest:seg-mix#c6",
    "digest:seg-mix#c24"
   ]
  },
  {
   "step": "model-impact",
   "text": "The largest cell is mostly empty; weight belongs in colocation",
   "refs": [
    "ledger:geo.DE",
    "ledger:seg.colocation",
    "profile:Who is the primary buyer you'll sell through first?"
   ]
  }
 ],
 "falsifier": "A Europe- or CE-scoped split showing hyperscale-owned capacity at 40% or more of CE-7 total data-center capacity.",
 "category": "model-structure",
 "evidence": [
  {
   "title": "CBRE: European hyperscaler self-build capacity growth to outpace colocation supply growth",
   "sourceType": "industry-report",
   "publisher": "DatacenterDynamics / CBRE",
   "date": "2026-02-20",
   "excerpt": "60 percent of Europe’s operational hyperscale self-build capacity located in Ireland, the Netherlands, Sweden, and Belgium... The colocation segment is expected to remain about 50 percent larger than the self-build segment at the end of 2026.",
   "url": "https://www.datacenterdynamics.com/en/news/cbre-european-hyperscaler-self-build-capacity-growth-to-outpace-colocation-supply-growth-but-supply-outpaces-take-up-in-weaker-than-expected-2025/",
   "attached": true
  },
  {
   "title": "Data Centres in Europe: Starting the Year on a High Note",
   "sourceType": "industry-report",
   "publisher": "CBRE Research",
   "date": "2023-02",
   "excerpt": "CBRE exclusively tracks third-party carrier neutral colocation data centres across Europe... Hyperscalers / cloud service providers responsible for the huge volume of take up across Europe.",
   "url": "https://www.dutchdatacenters.nl/wp-content/uploads/2023/03/CBRE-Europe-Data-Centres-Overview-KSE23.pdf",
   "attached": true
  },
  {
   "title": "Frankfurt DCI Report 2024",
   "sourceType": "industry-report",
   "publisher": "Structure Research",
   "date": "2024-06-24",
   "excerpt": "Hyperscale clouds have built out significant footprints... Hyperscale colocation is growing at a five-year CAGR of 26.1% and retail colocation is moving along at a 10.3% clip.",
   "url": "https://www.structureresearch.net/product/frankfurt-dci-report-2024-data-centre-colocation-hyperscale-cloud-interconnection/",
   "attached": true
  }
 ]
}

THE LEDGER FACTS IT TARGETS (current values, derivations, bands):
[
 {
  "id": "seg.hyperscale",
  "label": "Hyperscale",
  "kind": "estimated",
  "value": 0.44,
  "unit": "ratio",
  "confidence": "inferred",
  "maturity": "triangulated",
  "dimension": "segment",
  "dimensionValue": "hyperscale",
  "sensitivityRange": {
   "low": 0.4,
   "high": 0.48
  },
  "funnelActive": true,
  "derivation": {
   "method": "Capacity-split rescaling",
   "expression": "Synergy end-2025 hyperscale 48% × 0.91 (edge+telecom carve-out) = 0.44",
   "crossCheck": "Synergy Q1-2025 vintage: 44% — brackets the band"
  },
  "provenance": {
   "rationale": "Multiple Synergy vintages (41→48% through 2025) agree on trajectory; global split applied to CE → inferred.",
   "promotionPath": "Replace with a Europe-scoped capacity split when CBRE/Synergy publish one."
  },
  "evidence": [
   {
    "title": "Hyperscale operators to account for 67% of all data center capacity by 2031",
    "sourceType": "industry-report",
    "publisher": "Synergy Research Group",
    "date": "2026",
    "excerpt": "They now account for 48% of the worldwide capacity of all data centers... non-hyperscale colocation capacity accounting for another 20%... leaves enterprise on-premise data centers with just 32%.",
    "attached": true
   },
   {
    "title": "Hyperscale operators and colocation continue to drive huge changes",
    "sourceType": "industry-report",
    "publisher": "Synergy Research Group",
    "date": "2025-06-24",
    "excerpt": "They now account for 44% of the worldwide capacity of all data centers (Q1 2025 vintage).",
    "attached": true
   }
  ]
 },
 {
  "id": "seg.colocation",
  "label": "Colocation",
  "kind": "estimated",
  "value": 0.18,
  "unit": "ratio",
  "confidence": "inferred",
  "maturity": "single-source",
  "dimension": "segment",
  "dimensionValue": "colocation",
  "sensitivityRange": null,
  "funnelActive": true,
  "derivation": {
   "method": "Capacity-split rescaling",
   "expression": "Synergy end-2025 non-hyperscale colocation 20% × 0.91 = 0.18"
  },
  "provenance": {
   "rationale": "Single publisher's capacity series (20–22% across vintages), global scope applied to CE → inferred."
  },
  "evidence": [
   {
    "title": "Hyperscale operators to account for 67% of all data center capacity by 2031",
    "sourceType": "industry-report",
    "publisher": "Synergy Research Group",
    "date": "2026",
    "excerpt": "Non-hyperscale colocation capacity accounting for another 20% of total capacity (end-2025).",
    "attached": true
   }
  ]
 }
]

Emit JSON: { resolution: "error"|"risk", settleTest, proposedCorrection: {nodeId, value, low, high, rationale} or null, researchQueries: [{query, kind}] ([] for risks) }
